function r(r){const t=Date.now(),e=new Date(r).getTime(),a=Math.floor((t-e)/1e3);return a<60?"刚刚":a<3600?`${Math.floor(a/60)}分钟前`:a<86400?`${Math.floor(a/3600)}小时前`:a<172800?"昨天":a<604800?`${Math.floor(a/86400)}天前`:new Date(r).toLocaleDateString("zh-CN",{month:"short",day:"numeric"})}function t(r){if(!r)return"";const t=Math.floor(r/60),e=Math.floor(r%60);return 0===t?`${e}秒`:e>0?`${t}分${e}秒`:`${t}分钟`}function e(r){const t=Math.floor(r/60),e=Math.floor(r%60);return`${String(t).padStart(2,"0")}:${String(e).padStart(2,"0")}`}function a(r){return r?r.replace(/\*\*(.+?)\*\*/g,"<strong>$1</strong>").replace(/### (.+)/g,"<h4>$1</h4>").replace(/## (.+)/g,"<h3>$1</h3>").replace(/^- (.+)/gm,"<li>$1</li>").replace(/^\d+\.\s+(.+)/gm,"<li>$1</li>").replace(/---/g,"<hr/>").replace(/\n\n/g,"</p><p>").replace(/\n/g,"<br/>"):""}export{e as a,a as b,t as f,r};
